// Fetch recently published posts that haven't been distributed yet
const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' };

// Get posts published in last 48h
const since = new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString();
let posts;
try {
  posts = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/posts?select=id,title,slug,excerpt,category,image_url,created_at,seo_score,primary_keyword,meta_description&status=eq.published&created_at=gte.' + since + '&order=created_at.desc&limit=10',
    headers: headers, json: true
  });
} catch (e) { posts = []; }

if (!Array.isArray(posts)) posts = [];

// Get already distributed post IDs
let distributed;
try {
  const postIds = posts.map(p => p.id);
  if (postIds.length > 0) {
    distributed = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/post_distributions?select=post_id,channel&post_id=in.(' + postIds.join(',') + ')',
      headers: headers, json: true
    });
  } else { distributed = []; }
} catch (e) { distributed = []; }
if (!Array.isArray(distributed)) distributed = [];

const distributedSet = new Set(distributed.map(d => d.post_id + ':' + d.channel));

const SITE_URL = $env.SITE_URL || 'https://vision7.pt';
const channels = ['sitemap', 'twitter', 'linkedin'];

const output = [];
for (const post of posts) {
  for (const channel of channels) {
    const key = post.id + ':' + channel;
    if (!distributedSet.has(key)) {
      output.push({
        json: {
          post_id: post.id,
          title: post.title,
          slug: post.slug,
          excerpt: post.excerpt || '',
          image_url: post.image_url || '',
          category: post.category || 'geral',
          primary_keyword: post.primary_keyword || '',
          meta_description: post.meta_description || post.excerpt || '',
          post_url: SITE_URL + '/post/' + post.slug,
          channel: channel,
          created_at: post.created_at
        }
      });
    }
  }
}

if (output.length === 0) {
  return [{ json: { skip: true, message: 'No new posts to distribute' } }];
}

return output;

// Route by channel
const item = $json;
const channel = item.channel;

// All items pass through — downstream nodes filter by channel
return [{ json: { ...item } }];

// Sitemap + Google Indexing API ping
const post = $json;
if (post.channel !== 'sitemap') return [];

const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const SITE_URL = $env.SITE_URL || 'https://vision7.pt';
const headers = { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' };

// 1. Upsert sitemap entry
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/sitemap_entries',
    headers: { ...headers, 'Prefer': 'resolution=merge-duplicates' },
    body: {
      post_id: post.post_id,
      url: post.post_url,
      last_modified: new Date().toISOString(),
      changefreq: 'daily',
      priority: 0.8
    },
    json: true
  });
} catch (e) { /* may already exist */ }

// 2. Ping Google with updated sitemap URL
let googlePingResult = null;
try {
  const sitemapUrl = SITE_URL + '/sitemap.xml';
  googlePingResult = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.google.com/ping?sitemap=' + encodeURIComponent(sitemapUrl),
    returnFullResponse: true
  });
} catch (e) { googlePingResult = { error: e.message }; }

// 3. Record distribution
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/post_distributions',
    headers: headers,
    body: {
      post_id: post.post_id,
      channel: 'sitemap',
      status: 'sent',
      sent_at: new Date().toISOString(),
      external_url: post.post_url,
      engagement: { google_pinged: true }
    },
    json: true
  });
} catch (e) { /* ok */ }

return [{ json: { success: true, channel: 'sitemap', post_id: post.post_id, google_ping: googlePingResult ? 'ok' : 'failed' } }];

// Twitter/X distribution (requires TWITTER_BEARER_TOKEN env)
const post = $json;
if (post.channel !== 'twitter') return [];

const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' };
const twitterToken = $env.TWITTER_BEARER_TOKEN || '';

let result = { status: 'pending', external_id: null, error: null };

if (twitterToken) {
  try {
    // Compose tweet: title + excerpt + url + hashtag
    const hashtag = post.primary_keyword ? ' #' + post.primary_keyword.replace(/\s+/g, '') : '';
    const tweetText = post.title + '\n\n' + (post.excerpt || '').substring(0, 120) + '...\n\n' + post.post_url + hashtag + ' #Vision7 #Tech';

    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.twitter.com/2/tweets',
      headers: { 'Authorization': 'Bearer ' + twitterToken, 'Content-Type': 'application/json' },
      body: { text: tweetText.substring(0, 280) },
      json: true
    });
    result = { status: 'sent', external_id: resp.data?.id || null, error: null };
  } catch (e) {
    result = { status: 'failed', external_id: null, error: e.message };
  }
} else {
  result = { status: 'pending', external_id: null, error: 'TWITTER_BEARER_TOKEN not configured' };
}

// Record distribution
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/post_distributions',
    headers: headers,
    body: {
      post_id: post.post_id,
      channel: 'twitter',
      status: result.status,
      sent_at: result.status === 'sent' ? new Date().toISOString() : null,
      external_id: result.external_id,
      error_detail: result.error
    },
    json: true
  });
} catch (e) { /* ok */ }

return [{ json: { success: result.status === 'sent', channel: 'twitter', post_id: post.post_id, tweet_id: result.external_id, error: result.error } }];

// LinkedIn distribution (requires LINKEDIN_ACCESS_TOKEN env)
const post = $json;
if (post.channel !== 'linkedin') return [];

const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' };
const linkedinToken = $env.LINKEDIN_ACCESS_TOKEN || '';
const linkedinAuthorId = $env.LINKEDIN_AUTHOR_ID || '';

let result = { status: 'pending', external_id: null, error: null };

if (linkedinToken && linkedinAuthorId) {
  try {
    const shareText = post.title + '\n\n' + (post.excerpt || '').substring(0, 200) + '\n\nLer mais: ' + post.post_url + '\n\n#Vision7 #Tecnologia';

    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.linkedin.com/v2/ugcPosts',
      headers: { 'Authorization': 'Bearer ' + linkedinToken, 'Content-Type': 'application/json', 'X-Restli-Protocol-Version': '2.0.0' },
      body: {
        author: 'urn:li:person:' + linkedinAuthorId,
        lifecycleState: 'PUBLISHED',
        specificContent: {
          'com.linkedin.ugc.ShareContent': {
            shareCommentary: { text: shareText.substring(0, 700) },
            shareMediaCategory: 'ARTICLE',
            media: [{
              status: 'READY',
              originalUrl: post.post_url,
              title: { text: post.title },
              description: { text: post.meta_description || post.excerpt || '' }
            }]
          }
        },
        visibility: { 'com.linkedin.ugc.MemberNetworkVisibility': 'PUBLIC' }
      },
      json: true
    });
    result = { status: 'sent', external_id: resp.id || null, error: null };
  } catch (e) {
    result = { status: 'failed', external_id: null, error: e.message };
  }
} else {
  result = { status: 'pending', external_id: null, error: 'LINKEDIN_ACCESS_TOKEN or LINKEDIN_AUTHOR_ID not configured' };
}

// Record distribution
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/post_distributions',
    headers: headers,
    body: {
      post_id: post.post_id,
      channel: 'linkedin',
      status: result.status,
      sent_at: result.status === 'sent' ? new Date().toISOString() : null,
      external_id: result.external_id,
      error_detail: result.error
    },
    json: true
  });
} catch (e) { /* ok */ }

return [{ json: { success: result.status === 'sent', channel: 'linkedin', post_id: post.post_id, error: result.error } }];
